40	const PROCESSING_FEE = 5;
41	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
42	const CURSE_SURCHARGE_RATE = 0.5;
43	const HIGH_ENCHANTMENT_THRESHOLD = 5;
44	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
45	const LOYALTY_YEARS_THRESHOLD = 2;
46	const LOYALTY_DISCOUNT_RATE = 0.2;
47	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
48	const COMPONENT_BLOCK_SIZE = 3;
49	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
50	const DEDUCTIBLE = 100;
51	const HIGH_REIMBURSEMENT_ENCHANTMENT_THRESHOLD = 8;
52	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
53	const FULL_REIMBURSEMENT_RATE = 1;
54	const CAP_MULTIPLIER = 2;
55	
56	const BASE_PREMIUMS: Record<string, number> = {
57	  sword: 100,
58	  amulet: 60,
59	  staff: 80,
60	  potion: 40,
61	  rune: 25,
62	  moonstone: 25,
63	};
64	
65	const INSURANCE_VALUES: Record<string, number> = {
66	  sword: 1000,
67	  rune: 250,
68	};
69	
70	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
71	
72	const isComponentBlock = (type: string, count: number): boolean =>
73	  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE;
74	
75	const basePremiumFor = (type: string): number => {
76	  const basePremium = BASE_PREMIUMS[type];
77	  if (basePremium === undefined) {
78	    throw new Error(`Unknown item type: ${type}`);
79	  }
80	  return basePremium;
81	};
82	
83	const surchargeFor = (
84	  items: Item[],
85	  applies: (item: Item) => boolean,
86	  rate: number
87	): number =>
88	  items.reduce(
89	    (surcharge, item) =>
90	      applies(item) ? surcharge + basePremiumFor(item.type) * rate : surcharge,
91	    0
92	  );
93	
94	const isCursed = (item: Item): boolean => item.cursed === true;
95	
96	const hasEnchantmentAtLeast = (
97	  item: Item | undefined,
98	  threshold: number
99	): boolean => (item?.enchantment ?? 0) >= threshold;
100	
101	const isHighlyEnchanted = (item: Item): boolean =>
102	  hasEnchantmentAtLeast(item, HIGH_ENCHANTMENT_THRESHOLD);
103	
104	const curseSurchargeFor = (items: Item[]): number =>
105	  surchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
106	
107	const enchantmentSurchargeFor = (items: Item[]): number =>
108	  surchargeFor(items, isHighlyEnchanted, HIGH_ENCHANTMENT_SURCHARGE_RATE);
109	
110	const groupBasePremium = (type: string, count: number): number =>
111	  isComponentBlock(type, count)
112	    ? COMPONENT_BLOCK_BASE_PREMIUM
113	    : count * basePremiumFor(type);
114	
115	const policyBaseFor = (items: Item[]): number => {
116	  const countsByType = new Map<string, number>();
117	  for (const item of items) {
118	    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
119	  }
120	
121	  let policyBase = 0;
122	  for (const [type, count] of countsByType) {
123	    policyBase += groupBasePremium(type, count);
124	  }
125	  return policyBase;
126	};
127	
128	const qualifiesForLoyaltyDiscount = (customer: Customer): boolean =>
129	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
130	
131	const quotePremium = (
132	  items: Item[],
133	  customer: Customer,
134	  isFollowUp: boolean
135	): number => {
136	  const policyBase = policyBaseFor(items);
137	  const itemSurcharges =
138	    curseSurchargeFor(items) + enchantmentSurchargeFor(items);
139	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
140	  const loyaltyDiscount = qualifiesForLoyaltyDiscount(customer)
141	    ? policyBase * LOYALTY_DISCOUNT_RATE
142	    : 0;
143	  const followUpDiscount = isFollowUp
144	    ? policyBase * FOLLOW_UP_DISCOUNT_RATE
145	    : 0;
146	  return Math.ceil(
147	    policyBase +
148	      itemSurcharges +
149	      firstInsuranceSurcharge -
150	      loyaltyDiscount -
151	      followUpDiscount +
152	      PROCESSING_FEE
153	  );
154	};
155	
156	const isFollowUpQuote = (stepIndex: number): boolean => stepIndex > 0;
157	
158	const insuranceSumFor = (items: Item[]): number =>
159	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
160	
161	const reimbursementRateFor = (damagedItem: Item | undefined): number =>
162	  hasEnchantmentAtLeast(damagedItem, HIGH_REIMBURSEMENT_ENCHANTMENT_THRESHOLD)
163	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
164	    : FULL_REIMBURSEMENT_RATE;
165	
166	const processClaim = (step: Step, steps: Step[]): unknown => {
167	  const policyItems = steps[step.policy!].items ?? [];
168	  const payoutCap = insuranceSumFor(policyItems) * CAP_MULTIPLIER;
169	  const damage = step.incident!.damages[0];
170	  const damagedItem = policyItems.find((item) => item.type === damage.itemType);
171	  const payout =
172	    damage.amount * reimbursementRateFor(damagedItem) - DEDUCTIBLE;
173	  return { payout, remainingCap: payoutCap - payout };
174	};
175	
176	export const processScenario = (input: ScenarioInput): ScenarioOutput => {
177	  const results = input.steps.map((step, index) =>
178	    step.op === "claim"
179	      ? processClaim(step, input.steps)
180	      : {
181	          premium: quotePremium(
182	            step.items ?? [],
183	            input.customer,
184	            isFollowUpQuote(index)
185	          ),
186	        }
187	  );
188	  return { results };
189	};
